391→/// A polynomial of 512 Zq coefficients packed into 29 felt252 fields.
392→/// Suitable for Starknet storage (each field maps to a single storage slot).
393→#[derive(Drop, Copy, Serde)]
394→pub struct PackedPolynomial512 {
395→    pub s0: felt252,
396→    pub s1: felt252,
397→    pub s2: felt252,
398→    pub s3: felt252,
399→    pub s4: felt252,
400→    pub s5: felt252,
401→    pub s6: felt252,
402→    pub s7: felt252,
403→    pub s8: felt252,
404→    pub s9: felt252,
405→    pub s10: felt252,
406→    pub s11: felt252,
407→    pub s12: felt252,
408→    pub s13: felt252,
409→    pub s14: felt252,
410→    pub s15: felt252,
411→    pub s16: felt252,
412→    pub s17: felt252,
413→    pub s18: felt252,
414→    pub s19: felt252,
415→    pub s20: felt252,
416→    pub s21: felt252,
417→    pub s22: felt252,
418→    pub s23: felt252,
419→    pub s24: felt252,
420→    pub s25: felt252,
421→    pub s26: felt252,
422→    pub s27: felt252,
423→    pub s28: felt252,
424→}
