  5→use corelib_imports::bounded_int::{BoundedInt, downcast, upcast};
  6→use falcon::types::{
  7→    FalconPublicKey, FalconSignature, FalconSignatureWithHint, FalconVerificationHint, HashToPoint,
  8→    PackedFalconSignatureWithHint,
  9→};
 10→use crate::ntt::ntt_fast;
 11→use crate::packing::{PackedPolynomial512, PackedPolynomial512Trait};
 12→use crate::zq::{Zq, mul_mod, sub_mod};
 13→
 14→/// Zq value in the low half: [0, (Q-1)/2] = [0, 6144]
 15→type ZqLow = BoundedInt<0, 6144>;
 16→const Q_felt252: felt252 = 12289;
 17→
 18→/// Compute the squared centered norm of a single Zq element.
 19→fn center_and_square(coeff: Zq) -> felt252 {
 20→    match downcast::<Zq, ZqLow>(coeff) {
 21→        Option::Some(low) => {
 22→            let x: felt252 = upcast(low);
 23→            x * x
 24→        },
 25→        Option::None => {
 26→            let x: felt252 = upcast(coeff);
 27→            let centered = Q_felt252 - x;
 28→            centered * centered
 29→        },
 30→    }
 31→}
 32→
 33→/// Signature bound for Falcon-512
 34→const SIG_BOUND_512: u64 = 34034726;
 35→
 36→/// Verify a Falcon signature using the hint-based approach.
 37→/// Computes msg_point internally via hash_to_point.
 38→/// Cost: 2 NTTs, 0 INTTs.
 39→pub fn verify<H, +HashToPoint<H>, +Drop<H>>(
 40→    pk: @FalconPublicKey, sig_with_hint: FalconSignatureWithHint, message: Span<felt252>,
 41→) -> bool {
 42→    let salt_span = sig_with_hint.signature.salt.span();
 43→    let msg_point = HashToPoint::<H>::hash_to_point(message, salt_span);
 44→    verify_with_msg_point(pk, sig_with_hint, msg_point.span())
 45→}
 46→
 47→/// Verify with a pre-computed msg_point (useful for testing without hash_to_point).
 48→///
 49→/// Single-pass verification: 2 unrolled NTTs + 1 fused loop that does
 50→/// hint verification, pointwise multiply check, and norm computation.
 51→pub fn verify_with_msg_point(
 52→    pk: @FalconPublicKey, sig_with_hint: FalconSignatureWithHint, msg_point: Span<Zq>,
 53→) -> bool {
 54→    let s1 = sig_with_hint.signature.s1.span();
 55→    let pk_ntt = pk.h_ntt.span();
 56→    let mul_hint = sig_with_hint.hint.mul_hint.span();
 57→
 58→    assert!(s1.len() == 512, "s1 must be 512 elements");
 59→    assert!(pk_ntt.len() == 512, "pk must be 512 elements");
 60→    assert!(mul_hint.len() == 512, "mul_hint must be 512 elements");
 61→    assert!(msg_point.len() == 512, "msg_point must be 512 elements");
 62→
 63→    // Two forward NTTs (unrolled, no loops)
 64→    let s1_ntt = ntt_fast(s1);
 65→    let hint_ntt = ntt_fast(mul_hint);
 66→
 67→    // Single pass over all 512 coefficients:
 68→    //   - Verify hint: s1_ntt[i] * pk_ntt[i] == NTT(mul_hint)[i]
 69→    //   - Accumulate: ||msg_point - mul_hint||² + ||s1||²
 70→    let mut s1_ntt_iter = s1_ntt.span();
 71→    let mut pk_ntt_iter = pk_ntt;
 72→    let mut hint_ntt_iter = hint_ntt.span();
 73→    let mut msg_iter = msg_point;
 74→    let mut hint_iter = mul_hint;
 75→    let mut s1_iter = s1;
 76→
 77→    let mut acc: felt252 = 0;
 78→    while let Some(s1n_box) = s1_ntt_iter.multi_pop_front::<8>() {
 79→        let [s1n0, s1n1, s1n2, s1n3, s1n4, s1n5, s1n6, s1n7] = s1n_box.unbox();
 80→        let [pkn0, pkn1, pkn2, pkn3, pkn4, pkn5, pkn6, pkn7] = pk_ntt_iter
 81→            .multi_pop_front::<8>()
 82→            .unwrap()
 83→            .unbox();
 84→        let [hn0, hn1, hn2, hn3, hn4, hn5, hn6, hn7] = hint_ntt_iter
 85→            .multi_pop_front::<8>()
 86→            .unwrap()
 87→            .unbox();
 88→        let [msg0, msg1, msg2, msg3, msg4, msg5, msg6, msg7] = msg_iter
 89→            .multi_pop_front::<8>()
 90→            .unwrap()
 91→            .unbox();
 92→        let [hint0, hint1, hint2, hint3, hint4, hint5, hint6, hint7] = hint_iter
 93→            .multi_pop_front::<8>()
 94→            .unwrap()
 95→            .unbox();
 96→        let [s1v0, s1v1, s1v2, s1v3, s1v4, s1v5, s1v6, s1v7] = s1_iter
 97→            .multi_pop_front::<8>()
 98→            .unwrap()
 99→            .unbox();
100→
101→        // Verify: NTT(s1)[i] * pk_ntt[i] == NTT(mul_hint)[i]
102→        assert(mul_mod(s1n0, pkn0) == hn0, 'hint mismatch');
103→        assert(mul_mod(s1n1, pkn1) == hn1, 'hint mismatch');
104→        assert(mul_mod(s1n2, pkn2) == hn2, 'hint mismatch');
105→        assert(mul_mod(s1n3, pkn3) == hn3, 'hint mismatch');
106→        assert(mul_mod(s1n4, pkn4) == hn4, 'hint mismatch');
107→        assert(mul_mod(s1n5, pkn5) == hn5, 'hint mismatch');
108→        assert(mul_mod(s1n6, pkn6) == hn6, 'hint mismatch');
109→        assert(mul_mod(s1n7, pkn7) == hn7, 'hint mismatch');
110→
111→        // Accumulate: ||msg_point - mul_hint||² + ||s1||²
112→        acc += center_and_square(sub_mod(msg0, hint0))
113→            + center_and_square(s1v0)
114→            + center_and_square(sub_mod(msg1, hint1))
115→            + center_and_square(s1v1)
116→            + center_and_square(sub_mod(msg2, hint2))
117→            + center_and_square(s1v2)
118→            + center_and_square(sub_mod(msg3, hint3))
119→            + center_and_square(s1v3)
120→            + center_and_square(sub_mod(msg4, hint4))
121→            + center_and_square(s1v4)
122→            + center_and_square(sub_mod(msg5, hint5))
123→            + center_and_square(s1v5)
124→            + center_and_square(sub_mod(msg6, hint6))
125→            + center_and_square(s1v6)
126→            + center_and_square(sub_mod(msg7, hint7))
127→            + center_and_square(s1v7);
128→    }
129→
130→    let norm_u64: u64 = acc.try_into().unwrap();
131→    norm_u64 <= SIG_BOUND_512
132→}
133→
134→/// Verify a Falcon signature from packed (29 felt252) inputs.
135→/// Unpacks PK, s1, and mul_hint, then delegates to verify.
136→pub fn verify_packed<H, +HashToPoint<H>, +Drop<H>>(
137→    pk: @PackedPolynomial512, sig: PackedFalconSignatureWithHint, message: Span<felt252>,
138→) -> bool {
139→    let pk_coeffs = pk.to_coeffs();
140→    let s1_coeffs = sig.signature.s1.to_coeffs();
141→    let mul_hint_coeffs = sig.hint.mul_hint.to_coeffs();
142→    let falcon_pk = FalconPublicKey { h_ntt: pk_coeffs };
143→    let sig_with_hint = FalconSignatureWithHint {
144→        signature: FalconSignature { s1: s1_coeffs, salt: sig.signature.salt },
145→        hint: FalconVerificationHint { mul_hint: mul_hint_coeffs },
146→    };
147→    verify::<H>(@falcon_pk, sig_with_hint, message)
148→}
