    registry.set(keypairAtom, Option.some(mockKeypair))
    const val = Option.getOrThrow(registry.get(keypairAtom))
    expect(val.secretKey).toBe(sk)
    expect(val.verifyingKey).toBe(vk)
    expect(val.publicKeyNtt).toBe(ntt)
